import React, { useState } from 'react';
import { TouchableOpacity, Text } from 'react-native';
import { useBiometrics } from 'react-native-biometrics';
import AsyncStorage from '@react-native-community/async-storage';

const BiometricAuth = () => {
  const [authenticated, setAuthenticated] = useState(false);

  const { isAvailable, authenticate } = useBiometrics();

  const handleAuthentication = async () => {
    if (!isAvailable) {
      // Fallback to password authentication or redirect to login screen
      console.log('Biometric authentication not available. Using password.');
      return;
    }

    try {
      await authenticate();
      setAuthenticated(true);
      await AsyncStorage.setItem('authenticated', 'true');
    } catch (error) {
      console.log('Biometric authentication failed.', error);
      // Handle authentication errors
    }
  };

  return (
    <TouchableOpacity onPress={handleAuthentication}>
      <Text>{authenticated ? 'Authenticated' : 'Authenticate'}</Text>
    </TouchableOpacity>
  );
};

export default BiometricAuth;